#include <climits>\n#include <cstdint>\n#include <iostream>\n#include <string>\n#include <vector>\n\nclass PrimeNumbers {  // 0 = false, 1 = false, 2 = true ...\n public:\n  PrimeNumbers() {\n    s_.resize(3, false);\n    s_[2] = true;\n  }\n\n  bool IsPrime(size_t number) {\n    if (number >= s_.size()) {\n      Fill(number);\n    }\n    return s_[number];\n  }\n\n  size_t GetNext(size_t number) {\n    for (size_t i = number; i < s_.size(); i++) {\n      if (s_[i]) return i;\n    }\n    Fill(number * 2);\n    return GetNext(number);\n  }\n\n private:\n  void Fill(size_t number) {\n    auto old_size = s_.size();\n    if (old_size <= number) {\n      s_.resize(number + 1, true);\n      for (size_t i = 2; i < s_.size(); i++) {\n        if (s_[i]) {\n          for (size_t j = 2 * i; j < s_.size(); j += i) {\n            if (j >= old_size) s_[j] = false;\n          }\n        }\n      }\n    }\n    \n  }\n  std::vector<bool> s_;\n};\n\nint64_t static Gcd(int64_t a, int64_t b) {\n  if (a == 0 || b == 0) {\n    return a + b;\n  }\n  if (a > b) {\n    return Gcd(a % b, b);\n  }\n  return Gcd(a, b % a);\n}\n\nint64_t static Pow(int64_t base, int64_t exp, int64_t mod) {\n  if (exp == 0) {\n    return 1;\n  }\n  if (exp % 2 == 0) {\n    auto p = Pow(base, exp / 2, mod) % mod;\n    return (p * p) % mod;\n  }\n  return (base * Pow(base, exp - 1, mod)) % mod;\n}\n\nstatic int64_t Hash(const std::string& value, int64_t x, int64_t p) {\n  auto h = 0LL;\n  auto n = value.size();\n  h += value[0] % p;\n  for (size_t i = n - 1; i > 0; i--) {\n    h += value[i] * Pow(x, i, p) % p;\n    h %= p;\n  }\n  return h;\n}\n\nstatic inline int64_t FirstHash(const std::string& value) {\n  return Hash(value, 263, 1'000'000'007);\n}\n\nstatic inline int64_t SecondHash(const std::string& value) {\n  return Hash(value, 569, 2'024'202'409);  // 337, 2024'2111);\n}\n\ntemplate <class T, int64_t (*Hash)(const T&), int64_t (*Hash_2)(const T&)>\nclass HashTable {\n public:\n  HashTable(size_t size = 7) {\n    size_ = 0;\n    table_.resize(size, nullptr);\n  }\n\n  ~HashTable() {\n    for (size_t i = 0; i < table_.size(); i++) {\n      if (table_[i]) {\n        delete table_[i];\n        size_--;\n      }\n    }\n  }\n\n  void Push(T value) {\n    if (size_ >= 0.5 * table_.size()) {\n      Resize();\n    }\n    if (!Search(value)) {\n      auto index = Hash(value) % table_.size();\n      if (!table_[index]) {\n        table_[index] = new T(value);\n        size_++;\n        return;\n      }\n      auto step = Hash_2(value) % table_.size();\n      if (step == 0) {\n        step++;\n      }\n      for (size_t i = (index + step) % table_.size(); i != index;\n           i = (i + step) % table_.size()) {\n        if (!table_[i]) {\n          table_[i] = new T(value);\n          size_++;\n          return;\n        }\n      }\n    }\n  }\n\n  bool Pop(const T& value) {\n    auto index = GetIndex(value);\n    if (index != -1) {\n      delete table_[index];\n      table_[index] = nullptr;\n      size_--;\n      return true;\n    }\n    return false;\n  }\n\n  inline bool Search(const T& value) { return GetIndex(value) != -1; }\n\n  void Print() {\n    for (size_t i = 0; i < table_.size(); i++) {\n      std::cout << i << \" -> \";\n      if (table_[i]) {\n        std::cout << *table_[i] << std::endl;\n      } else {\n        std::cout << \"nullptr\" << std::endl;\n      }\n    }\n    std::cout << std::endl;\n  }\n\n private:\n  inline void Resize() { table_.resize(primes.GetNext(table_.size() + 1), nullptr); }\n\n  size_t GetIndex(const T& value) {\n    // -1, если нет. 0...table_.size() - 1, если есть\n    auto index = Hash(value) % table_.size();\n    if (table_[index] && *table_[index] == value) {\n      return index;\n    }\n\n    auto step = Hash_2(value) % table_.size();\n    if (step == 0) {\n      step++;\n    }\n    for (size_t i = (index + step) % table_.size(); i != index;\n         i = (i + step) % table_.size()) {\n      if (table_[i] && *table_[i] == value) {\n        return i;\n      }\n    }\n    return -1;\n  }\n\n  std::vector<T*> table_;\n  size_t size_;\n  PrimeNumbers primes;\n};\n\nint main() {\n  HashTable<std::string, FirstHash, SecondHash> table;\n  int n;\n  std::cin >> n;\n  for (int i = 0; i < n; i++) {\n    std::string command, word;\n    std::cin >> command >> word;\n\n    if (command == \"push\") {\n      table.Push(word);\n\n    } else if (command == \"pop\") {\n      if (table.Pop(word)) {\n        std::cout << \"TRUE\" << std::endl;\n      } else {\n        std::cout << \"FALSE\" << std::endl;\n      }\n\n    } else {  // command == \"Search\"\n      if (table.Search(word)) {\n        std::cout << \"TRUE\" << std::endl;\n      } else {\n        std::cout << \"FALSE\" << std::endl;\n      }\n    }\n    // table.Print();\n  }\n  return 0;\n}\n